#include <bits/stdc++.h>using namespace std;typedef long long ll;int main(){    ll t;    cin>>t;    while(t--){        ll n;        string s;        cin>>n;        cin>>s;        ll add=0;        ll one=0;        ll tot=0;        ll sub=0;        for(int i=0;i<n;i++){            if(s[i]=='0'){                if((i-1)>=0&&(i+1)<n&&s[i-1]=='1'&&s[i+1]=='1'){                    tot++;                    s[i]='1';                }            }            else{                tot++;            }        }        for(int i=0;i<n;i++){            if(s[i]=='1')one++;            else {                sub+=(one-1)/2;                one=0;            }        }        sub+=(one-1)/2;        cout<<(tot-sub)<<" "<<tot<<endl;    }}